# Utility classes and interfaces module

interface IIdentifiable:
    """Interface for objects that can be identified"""
    def get_id(self) -> int:
        ...

class IdGenerator:
    """Static utility class for generating unique IDs"""
    @static
    _counter: int = 0

    @staticmethod
    def next_id() -> int:
        IdGenerator._counter = IdGenerator._counter + 1
        return IdGenerator._counter

class NamedShape:
    """Class demonstrating fields and methods instead of properties"""
    _name: str
    _enabled: bool

    def __init__(self, name: str):
        self._name = name
        self._enabled = True

    def get_name(self) -> str:
        return self._name

    def is_enabled(self) -> bool:
        return self._enabled

    def set_enabled(self, value: bool):
        self._enabled = value

    def get_status(self) -> str:
        if self._enabled:
            return self._name + " is enabled"
        return self._name + " is disabled"

class MetricsCollector:
    """Collects and computes statistics on shapes"""
    _areas: list[float]

    def __init__(self):
        self._areas = []

    def add_area(self, area: float):
        self._areas.append(area)

    def average(self) -> float:
        if len(self._areas) == 0:
            return 0.0
        total: float = 0.0
        for a in self._areas:
            total = total + a
        return total / float(len(self._areas))
